import requests

from util.aes_help import HM_AES_IV, HM_AES_KEY, encrypt_data
from util.time_util import get_time_ms, today_str


REQUEST_TIMEOUT = 10


def login_access_token(user: str, password: str) -> tuple[str | None, str | None]:
    """通过用户名密码获取 access_token。"""
    headers = {
        "content-type": "application/x-www-form-urlencoded; charset=UTF-8",
        "user-agent": "MiFit6.14.0 (M2007J1SC; Android 12; Density/2.75)",
        "app_name": "com.xiaomi.hm.health",
        "appname": "com.xiaomi.hm.health",
        "appplatform": "android_phone",
        "x-hm-ekv": "1",
        "hm-privacy-ceip": "false",
    }
    url = "https://api-user.huami.com/v2/registrations/tokens"
    login_data = {
        "emailOrPhone": user,
        "password": password,
        "state": "REDIRECTION",
        "client_id": "HuaMi",
        "country_code": "CN",
        "token": "access",
        "redirect_uri": "https://s3-us-west-2.amazonaws.com/hm-registration/successsignin.html",
    }
    query = urllib.parse.urlencode(login_data)
    cipher_data = encrypt_data(query.encode("utf-8"), HM_AES_KEY, HM_AES_IV)

    try:
        response = requests.post(
            url,
            data=cipher_data,
            headers=headers,
            allow_redirects=False,
            timeout=REQUEST_TIMEOUT,
        )
    except requests.exceptions.RequestException as exc:
        return None, f"登录请求网络异常：{exc}"

    if response.status_code != 303:
        return None, f"登录异常，status: {response.status_code}"

    try:
        location = response.headers["Location"]
        code = get_access_token(location)
        if code is None:
            return None, f"获取 access_token 失败：{get_error_code(location)}"
        return code, None
    except Exception:
        return None, f"获取 access_token 异常：{traceback.format_exc()}"


def get_access_token(location: str) -> str | None:
    code_pattern = re.compile(r"(?<=access=)[^&]+")
    result = code_pattern.findall(location)
    return result[0] if result else None


def get_error_code(location: str) -> str | None:
    code_pattern = re.compile(r"(?<=error=)[^&]+")
    result = code_pattern.findall(location)
    return result[0] if result else None


def grant_login_tokens(
    access_token: str | None,
    device_id: str,
    is_phone: bool = False,
) -> tuple[str | None, str | None, str | None, str | None]:
    """使用 access_token 换取 login_token 和 app_token。"""
    if not access_token:
        return None, None, None, "access_token 为空"

    url = "https://account.huami.com/v2/client/login"
    headers = {
        "app_name": "com.xiaomi.hm.health",
        "x-request-id": str(uuid.uuid4()),
        "accept-language": "zh-CN",
        "appname": "com.xiaomi.hm.health",
        "cv": "50818_6.14.0",
        "v": "2.0",
        "appplatform": "android_phone",
        "content-type": "application/x-www-form-urlencoded; charset=UTF-8",
    }
    if is_phone:
        data = {
            "app_name": "com.xiaomi.hm.health",
            "app_version": "6.14.0",
            "code": access_token,
            "country_code": "CN",
            "device_id": device_id,
            "device_model": "phone",
            "grant_type": "access_token",
            "third_name": "huami_phone",
        }
    else:
        data = {
            "allow_registration": "false",
            "app_name": "com.xiaomi.hm.health",
            "app_version": "6.14.0",
            "code": access_token,
            "country_code": "CN",
            "device_id": device_id,
            "device_model": "android_phone",
            "dn": "account.zepp.com,api-user.zepp.com,api-mifit.zepp.com,api-watch.zepp.com,app-analytics.zepp.com,api-analytics.huami.com,auth.zepp.com",
            "grant_type": "access_token",
            "lang": "zh_CN",
            "os_version": "1.5.0",
            "source": "com.xiaomi.hm.health:6.14.0:50818",
            "third_name": "email",
        }

    try:
        response = requests.post(url, data=data, headers=headers, timeout=REQUEST_TIMEOUT)
    except requests.exceptions.RequestException as exc:
        return None, None, None, f"客户端登录请求网络异常：{exc}"

    if response.status_code != 200:
        return None, None, None, f"客户端登录请求异常，status: {response.status_code}"

    try:
        resp = response.json()
    except ValueError:
        return None, None, None, "客户端登录失败，响应不是合法 JSON"

    result = resp.get("result")
    if result != "ok":
        return None, None, None, f"客户端登录失败：{result or resp.get('message') or '未知错误'}"

    token_info = resp.get("token_info") or {}
    login_token = token_info.get("login_token")
    app_token = token_info.get("app_token")
    user_id = token_info.get("user_id")
    if not login_token or not app_token or not user_id:
        return None, None, None, f"提取 token 信息失败：{json.dumps(resp, ensure_ascii=False)}"
    return login_token, app_token, user_id, None


def grant_app_token(login_token: str | None) -> tuple[str | None, str | None]:
    """使用 login_token 刷新 app_token。"""
    if not login_token:
        return None, "login_token 为空"

    url = (
        "https://account-cn.huami.com/v1/client/app_tokens"
        "?app_name=com.xiaomi.hm.health"
        "&dn=api-user.huami.com%2Capi-mifit.huami.com%2Capp-analytics.huami.com"
        f"&login_token={login_token}"
    )
    headers = {"User-Agent": "MiFit/5.3.0 (iPhone; iOS 14.7.1; Scale/3.00)"}
    try:
        response = requests.get(url, headers=headers, timeout=REQUEST_TIMEOUT)
    except requests.exceptions.RequestException as exc:
        return None, f"刷新 app_token 网络异常：{exc}"

    if response.status_code != 200:
        return None, f"刷新 app_token 请求异常，status: {response.status_code}"

    try:
        resp = response.json()
    except ValueError:
        return None, "刷新 app_token 失败，响应不是合法 JSON"

    if resp.get("result") != "ok":
        return None, f"刷新 app_token 失败：{resp.get('error_code') or resp.get('message') or '未知错误'}"

    app_token = (resp.get("token_info") or {}).get("app_token")
    if not app_token:
        return None, f"刷新 app_token 失败：{json.dumps(resp, ensure_ascii=False)}"
    return app_token, None


def check_app_token(app_token: str | None, user_id: str | None = None) -> tuple[bool, str | None]:
    """检查 app_token 是否有效。"""
    if not app_token:
        return False, "app_token 为空"

    url = "https://api-mifit-cn3.zepp.com/huami.health.getUserInfo.json"
    params = {
        "r": str(uuid.uuid4()),
        "userid": user_id or "",
        "appid": "428135909242707968",
        "channel": "Normal",
        "country": "CN",
        "cv": "50818_6.14.0",
        "device": "android_31",
        "device_type": "android_phone",
        "lang": "zh_CN",
        "timezone": "Asia/Shanghai",
        "v": "2.0",
    }
    headers = {
        "User-Agent": "MiFit6.14.0 (M2007J1SC; Android 12; Density/2.75)",
        "Accept-Encoding": "gzip",
        "hm-privacy-diagnostics": "false",
        "country": "CN",
        "appplatform": "android_phone",
        "hm-privacy-ceip": "true",
        "x-request-id": str(uuid.uuid4()),
        "timezone": "Asia/Shanghai",
        "channel": "Normal",
        "cv": "50818_6.14.0",
        "appname": "com.xiaomi.hm.health",
        "v": "2.0",
        "apptoken": app_token,
        "lang": "zh_CN",
        "clientid": "428135909242707968",
    }

    try:
        response = requests.get(url, params=params, headers=headers, timeout=REQUEST_TIMEOUT)
    except requests.exceptions.RequestException as exc:
        return False, f"检查 app_token 网络异常：{exc}"

    if response.status_code != 200:
        return False, f"检查 app_token 请求异常，status: {response.status_code}"

    try:
        data = response.json()
    except ValueError:
        return False, "检查 app_token 失败，响应不是合法 JSON"

    message = data.get("message")
    if message == "success":
        return True, None
    return False, message or "未知错误"


def renew_login_token(login_token: str | None) -> tuple[str | None, str | None]:
    """刷新 login_token。"""
    if not login_token:
        return None, "login_token 为空"

    url = "https://account-cn3.zepp.com/v1/client/renew_login_token"
    params = {
        "os_version": "v0.8.1",
        "dn": "account.zepp.com,api-user.zepp.com,api-mifit.zepp.com,api-watch.zepp.com,app-analytics.zepp.com,api-analytics.huami.com,auth.zepp.com",
        "login_token": login_token,
        "source": "com.xiaomi.hm.health:6.14.0:50818",
        "timestamp": get_time_ms(),
    }
    headers = {
        "User-Agent": "MiFit6.14.0 (M2007J1SC; Android 12; Density/2.75)",
        "Accept-Encoding": "gzip",
        "app_name": "com.xiaomi.hm.health",
        "hm-privacy-ceip": "false",
        "x-request-id": str(uuid.uuid4()),
        "accept-language": "zh-CN",
        "appname": "com.xiaomi.hm.health",
        "cv": "50818_6.14.0",
        "v": "2.0",
        "appplatform": "android_phone",
    }

    try:
        response = requests.get(url, params=params, headers=headers, timeout=REQUEST_TIMEOUT)
    except requests.exceptions.RequestException as exc:
        return None, f"刷新 login_token 网络异常：{exc}"

    if response.status_code != 200:
        return None, f"刷新 login_token 请求异常，status: {response.status_code}"

    try:
        resp = response.json()
    except ValueError:
        return None, "刷新 login_token 失败，响应不是合法 JSON"

    if resp.get("result") != "ok":
        return None, f"刷新 login_token 失败：{resp.get('result') or resp.get('message') or '未知错误'}"

    new_login_token = (resp.get("token_info") or {}).get("login_token")
    if not new_login_token:
        return None, f"刷新 login_token 失败：{json.dumps(resp, ensure_ascii=False)}"
    return new_login_token, None


